class Solution:
    def findIntegers(self, n: int) -> int:
        dp = [[0, 0] for _ in range(31)]
        dp[0][0] = 1
        dp[0][1] = 1
        for i in range(1, 31):
            dp[i][0] = dp[i-1][0] + dp[i-1][1]
            dp[i][1] = dp[i-1][0]

        res = 0
        bit = 29
        prev_one = False
        while bit >= 0:
            if (n >> bit) & 1:
                res += dp[bit][0]
                if prev_one:
                    break
                prev_one = True
            else:
                prev_one = False
            bit -= 1
        return res + 1

